args.sparql:
SELECT ?voyager ?voyagerLabel WHERE {
  wd:Q41597 wdt:P1312 wd:Q708 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?destination ?destinationLabel WHERE {
  wd:Q41597 wdt:P1387 ?destination.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?mission ?destinationLabel WHERE {
  wd:Q41597 wdt:P3349 ?destination.
  SERVICE wikibase:label {bd:serviceParam wikibase:language "en"}
}
